mapper.select:
SELECT
    variable_id AS variableId,
    category_id AS categoryId,
    tier,
    var_code AS varCode
FROM emission_variable_def
WHERE category_id = #{categoryId}
  AND tier = #{tier}
  AND var_code = #{varCode}
LIMIT 1

SELECT COUNT(*)
FROM emission_variable_def
WHERE category_id = #{categoryId}
  AND tier = #{tier}

SELECT TO_CHAR(MAX(updated_at), 'YYYY-MM-DD HH24:MI:SS')
FROM emission_variable_def
WHERE category_id = #{categoryId}
  AND tier = #{tier}
